import Foundation

class Person {
    let name: String
    weak var partner: Person? // Use weak to break retain cycle

    init(name: String) {
        self.name = name
        print("\(name) initialized")
    }

    deinit {
        print("\(name) deallocated")
    }
}

print("Creating first person...")
var person1: Person? = Person(name: "Alice")

print("\nCreating second person and linking...")
var person2: Person? = Person(name: "Bob")
person1?.partner = person2
person2?.partner = person1

print("\nReleasing person1...")
person1 = nil

print("\nReleasing person2...")
person2 = nil

print("\nDone - both should be deallocated")

